# FactoryBot の定義
FactoryBot.define do
  factory :user do
    name     { Faker::Name.name }
    email    { Faker::Internet.unique.email }
    password { 'password123' }
    role     { 'user' }
    active   { true }

    # トレイト（バリエーション）
    trait :admin do
      role { 'admin' }
    end

    trait :inactive do
      active { false }
    end

    # 関連
    trait :with_posts do
      after(:create) do |user|
        create_list(:post, 3, user: user)
      end
    end
  end

  factory :post do
    title  { Faker::Lorem.sentence }
    body   { Faker::Lorem.paragraphs(number: 3).join('\n') }
    status { 'published' }
    association :user

    trait :draft do
      status { 'draft' }
    end
  end
end
